-- =============================================================================
-- CATEGORIES MODULE — SQLC QUERIES
-- File: db/queries/categories.sql
--
-- Type-safe Go for the Chart of Accounts + reconcile reference tables (categories,
-- transaction_types, transaction_type_categories — defined in categories_schema.sql).
-- Generated by a DEDICATED sqlc block (see sqlc.yaml) into package `categories` at
-- db/categories.
--
-- categories is PER-ORG; transaction_types + the mapping are GLOBAL reference. The
-- mapping SOFT-links categories by nominal_code (no FK across the global/per-org
-- boundary), resolved against the caller's org at query time.
--
-- Annotation syntax:
--   -- name: FuncName :one|:many|:exec
--   $1 ... positional params; sqlc.arg(name) for named; sqlc.embed(t) to nest a struct.
-- =============================================================================


-- -----------------------------------------------------------------------------
-- ListCategories — the org's whole active Chart of Accounts, by nominal code.
-- Populates the full category list / settings screen. Org-scoped. :many.
-- -----------------------------------------------------------------------------
-- name: ListCategories :many
SELECT * FROM categories
WHERE organisation_id = $1
  AND is_active
ORDER BY nominal_code;


-- -----------------------------------------------------------------------------
-- GetCategory — one category by id, org-scoped. :one.
-- -----------------------------------------------------------------------------
-- name: GetCategory :one
SELECT * FROM categories
WHERE id              = $1
  AND organisation_id = $2;


-- -----------------------------------------------------------------------------
-- ListSpendingCategories — the SPENDING subset of the org's CoA: the picker
-- shared by the bill form and the expense form. A bill/expense may only post to a
-- spending account, so income / balance-sheet / system-managed accounts are
-- excluded. Selects default_vat so the SPA can pre-select a sensible VAT rate when
-- a category is chosen. Org-scoped, active rows only. :many.
-- -----------------------------------------------------------------------------
-- name: ListSpendingCategories :many
SELECT id, nominal_code, name, account_type, api_group, default_vat
FROM categories
WHERE organisation_id = $1
  AND is_active
  AND is_system_managed = FALSE
  AND account_type IN ('COST_OF_SALES','ADMIN_EXPENSE','CAPITAL_ASSET')
ORDER BY account_type, nominal_code;


-- -----------------------------------------------------------------------------
-- ListTransactionTypes — the 18 explanation types (GLOBAL reference). :many.
-- Drives the "Type" dropdown, grouped by direction then display order.
-- -----------------------------------------------------------------------------
-- name: ListTransactionTypes :many
SELECT * FROM transaction_types
WHERE is_active
ORDER BY direction, display_order, name;


-- -----------------------------------------------------------------------------
-- ListCategoriesForType — EVERY category a transaction type offers, resolved
-- against the caller's org's CoA. The "which accounts can I pick for this type"
-- query — and each returned row IS the account that type-category pair posts to.
--
-- Joins the GLOBAL mapping (transaction_type_categories) to the PER-ORG categories
-- by nominal_code. company_type filters to the org: the 'ALL' rows always apply,
-- the rest only for a matching company_type (e.g. Money Paid to User differs Ltd
-- vs sole trader). display_label overrides the category name where the tab used a
-- friendlier label. :many.
-- -----------------------------------------------------------------------------
-- name: ListCategoriesForType :many
SELECT sqlc.embed(c), m.display_label
FROM transaction_type_categories m
JOIN categories c
  ON  c.organisation_id = sqlc.arg(organisation_id)
  AND c.is_active
  -- a mapping row targets EITHER a specific nominal OR a whole api_group
  AND ( (m.nominal_code <> '' AND c.nominal_code = m.nominal_code)
     OR (m.api_group   <> '' AND c.api_group     = m.api_group) )
WHERE m.transaction_type_code = sqlc.arg(transaction_type_code)
  AND (m.company_type = 'ALL' OR m.company_type = sqlc.arg(company_type))
ORDER BY m.display_order, c.nominal_code;


-- -----------------------------------------------------------------------------
-- GetTransactionType — one type by code (global reference). :one.
-- Used by the explain service to read a type's direction + entity_link.
-- -----------------------------------------------------------------------------
-- name: GetTransactionType :one
SELECT * FROM transaction_types WHERE code = $1;


-- -----------------------------------------------------------------------------
-- CategoryOfferedForType — does this type offer this nominal (for the org's
-- company_type)? Backs the explain service's "is this category valid for the
-- chosen type" guard. Returns the matching nominal_code(s) (empty = not offered).
-- -----------------------------------------------------------------------------
-- name: CategoryOfferedForType :one
SELECT EXISTS (
    SELECT 1
    FROM transaction_type_categories m
    JOIN categories c
      ON  c.organisation_id = sqlc.arg(organisation_id)
      AND c.is_active
      AND ( (m.nominal_code <> '' AND c.nominal_code = m.nominal_code)
         OR (m.api_group   <> '' AND c.api_group     = m.api_group) )
    WHERE m.transaction_type_code = sqlc.arg(transaction_type_code)
      AND (m.company_type = 'ALL' OR m.company_type = sqlc.arg(company_type))
      AND c.id = sqlc.arg(category_id)
) AS offered;


-- -----------------------------------------------------------------------------
-- GetVatRate — one VAT rate by id (for the VAT extraction on an explanation).
-- The frontend picks the id from GET /api/v1/vat-rates; the service reads rate_bps
-- and feeds money.ComputeFixedVAT. :one.
-- -----------------------------------------------------------------------------
-- name: GetVatRate :one
SELECT * FROM vat_rates WHERE id = $1;


-- -----------------------------------------------------------------------------
-- GENERAL-LEDGER RESOLVER SUPPORT
-- The ledger.Accounts resolver (internal/ledger) turns an account_role into a real
-- categories row. These back that: look up a control nominal, and find-or-create a
-- per-user sub-account of an is_user_subdivided parent (e.g. 908 Dividend → 908-1).
-- -----------------------------------------------------------------------------

-- name: GetCategoryByNominal :one
-- One active category by (org, nominal_code) — the natural-key lookup the resolver
-- uses for fixed-role nominals AND to inspect a picked category's account_type /
-- is_user_subdivided flag. :one.
SELECT * FROM categories
WHERE organisation_id = $1
  AND nominal_code    = sqlc.arg(nominal_code)
  AND is_active;

-- name: GetUserSubAccount :one
-- An existing per-user sub-account of a parent, for this org+user. The first half of
-- the resolver's idempotent find-or-create (idx_categories_user_subaccount guarantees
-- at most one). :one.
SELECT * FROM categories
WHERE organisation_id     = $1
  AND parent_nominal_code = sqlc.arg(parent_nominal_code)
  AND user_id             = sqlc.arg(user_id);

-- name: NextSubAccountSuffix :one
-- The next '-N' suffix for a parent in this org (1 if none yet): MAX(existing N)+1.
-- So 908's first sub-account is 908-1, the next 908-2, … Keyed only by org+parent, so
-- it serves BOTH user (908-x) and bank (750-x) sub-accounts. :one.
SELECT COALESCE(MAX(NULLIF(split_part(nominal_code, '-', 2), '')::int), 0) + 1 AS next_suffix
FROM categories
WHERE organisation_id     = $1
  AND parent_nominal_code = sqlc.arg(parent_nominal_code);

-- name: CreateUserSubAccount :one
-- Create a per-user sub-account row, inheriting the parent's account_type / api_group.
-- Always system-managed (never a free pick). RETURNING * so the resolver gets its id.
-- :one.
INSERT INTO categories (
    organisation_id, nominal_code, name, account_type, api_group,
    is_system_managed, parent_nominal_code, user_id
) VALUES (
    $1, sqlc.arg(nominal_code), sqlc.arg(name), sqlc.arg(account_type), sqlc.arg(api_group),
    TRUE, sqlc.arg(parent_nominal_code), sqlc.arg(user_id)
)
RETURNING *;

-- name: GetBankSubAccount :one
-- An existing 750-x sub-account for this org+bank account. The find half of the
-- resolver's idempotent find-or-create (idx_categories_bank_subaccount guarantees at
-- most one). :one.
SELECT * FROM categories
WHERE organisation_id     = $1
  AND parent_nominal_code = sqlc.arg(parent_nominal_code)
  AND bank_account_id     = sqlc.arg(bank_account_id);

-- name: CreateBankSubAccount :one
-- Create a per-bank-account sub-account row (750-x), inheriting the parent's
-- account_type / api_group. System-managed. RETURNING * for the resolver. :one.
INSERT INTO categories (
    organisation_id, nominal_code, name, account_type, api_group,
    is_system_managed, parent_nominal_code, bank_account_id
) VALUES (
    $1, sqlc.arg(nominal_code), sqlc.arg(name), sqlc.arg(account_type), sqlc.arg(api_group),
    TRUE, sqlc.arg(parent_nominal_code), sqlc.arg(bank_account_id)
)
RETURNING *;
